import{j as t,b as s,c as i,a9 as a}from"./chunks/framework.CFGK5tmi.js";const y=JSON.parse('{"title":"select语句期间发生了什么","description":"","frontmatter":{},"headers":[],"relativePath":"backend/db/mysql/select语句期间发生了什么.md","filePath":"backend/db/mysql/select语句期间发生了什么.md","lastUpdated":null}'),e={name:"backend/db/mysql/select语句期间发生了什么.md"},d=a(`<h1 id="select语句期间发生了什么" tabindex="-1">select语句期间发生了什么 <a class="header-anchor" href="#select语句期间发生了什么" aria-label="Permalink to &quot;select语句期间发生了什么&quot;">​</a></h1><p>以下面的语句为例子</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> product </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>下图是MySQL架构图，从中可以看到MySQL的各个模块，包含了：</p><ol><li>连接器</li><li>缓存</li><li>解析器</li><li>计划生成</li><li>调用存储引擎接口执行sql</li></ol><p><img src="https://yijina.oss-cn-chengdu.aliyuncs.com/img/mysql/mysql%E6%9F%A5%E8%AF%A2%E6%B5%81%E7%A8%8B.png" alt="查询语句执行流程"></p><p>可以看出来，MySQL是分成了Server层和存储引擎层的，它们的功能各不相同。</p><ul><li>Server层：<strong>负责建立连接、分析和执行 SQL</strong></li><li>存储引擎层：<strong>复制数据的存储和提取</strong>，我们常见的innodb、MyISAM都在这里</li></ul><h2 id="连接器" tabindex="-1">连接器 <a class="header-anchor" href="#连接器" aria-label="Permalink to &quot;连接器&quot;">​</a></h2><p>我们需要先连接到MySQL服务端，具体的写法如下，我自己为了方便在本机上也经常写<code>mysql -uroot -pabc123</code>，表示使用root登录，密码为abc123，ip地址如果是本机可以省略的。</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># -h 指定 MySQL 服务得 IP 地址，如果是连接本地的 MySQL服务，可以不用这个参数；</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># -u 指定用户名，管理员角色名为 root；</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># -p 指定密码，如果命令行中不填写密码（为了密码安全，建议不要在命令行写密码），就需要在交互对话里面输入密码</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mysql</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ip</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>如果用户密码都没有问题，连接器就会获取该用户的权限，然后保存起来，<strong>后续该用户在此连接里的任何操作，都会基于连接开始时读到的权限进行权限逻辑的判断</strong>。也就是说，就算中途修改了权限，也不会影响到已经完成的连接。</p><p>我们可以使用<code>show processlist</code>用于显示当前正在运行的线程信息。例如可能出现以下的信息</p><table tabindex="0"><thead><tr><th>Id</th><th>User</th><th>Host</th><th>db</th><th>Command</th><th>Time</th><th>State</th><th>Info</th></tr></thead><tbody><tr><td>1</td><td>root</td><td>localhost</td><td>mydatabase</td><td>Query</td><td>10</td><td>Sending data</td><td>SELECT * FROM users</td></tr><tr><td>2</td><td>root</td><td>localhost</td><td>NULL</td><td>Sleep</td><td>120</td><td></td><td>NULL</td></tr><tr><td>3</td><td>app_user</td><td>192.168.1.10:33306</td><td>app_db</td><td>Query</td><td>0</td><td>updating</td><td>UPDATE orders SET status=&#39;processed&#39; WHERE id=123</td></tr><tr><td>4</td><td>root</td><td>localhost</td><td>test_db</td><td>Sleep</td><td>5</td><td></td><td>NULL</td></tr><tr><td>5</td><td>guest</td><td>192.168.1.20:12345</td><td>guest_db</td><td>Query</td><td>15</td><td>Copying to tmp table</td><td>SELECT name, COUNT(*) FROM sales GROUP BY name</td></tr><tr><td>6</td><td>root</td><td>localhost</td><td>NULL</td><td>Sleep</td><td>200</td><td></td><td>NULL</td></tr><tr><td>7</td><td>root</td><td>localhost</td><td>test_db</td><td>Query</td><td>0</td><td>sorting result</td><td>SELECT * FROM products ORDER BY price DESC</td></tr><tr><td>8</td><td>backup</td><td>192.168.1.30:4444</td><td>NULL</td><td>Binlog Dump</td><td>300</td><td>Master has sent all binlog to slave; waiting for more updates</td><td>NULL</td></tr></tbody></table><p>可以看出来上面的id2是一个Sleep状态，这意味着该用户连接完 MySQL 服务就没有再执行过任何命令，也就是说这是一个空闲的连接，并且空闲的时长是 120 秒（ Time 列）。空闲连接不会一直占用，它由 <code>wait_timeout</code> 参数控制的，默认值是 8 小时（28880秒），如果空闲连接超过了这个时间，连接器就会自动将它断开。</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mysql</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> SHOW VARIABLES </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">LIKE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;wait_timeout&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>输出结果示例如下：</p><table tabindex="0"><thead><tr><th>Variable_name</th><th>Value</th></tr></thead><tbody><tr><td>wait_timeout</td><td>28800</td></tr></tbody></table><p>也可以自己断开他，比如使用<code>kill connection + id</code>的命令。MySQL也有最大连接限制，用<code>show variables like &#39;max_connections&#39;;</code>查看，默认151个</p><h2 id="查询缓存" tabindex="-1">查询缓存 <a class="header-anchor" href="#查询缓存" aria-label="Permalink to &quot;查询缓存&quot;">​</a></h2><p>如果是select查询语句，MySQL会去缓存中查询，看看之前有没有执行过这一条命令。</p><ul><li>如果查询的语句命中查询缓存，那么就会直接返回 value 给客户端。</li><li>如果查询的语句没有命中查询缓存中，那么就要往下继续执行，等执行完后，查询的结果就会被存入查询缓存中。</li></ul><p>但是对于更新频繁的表，只要有一个更新表的操作，缓存就会被清空，因此，从MySQL8开始，就把Server层的缓存功能去除了。</p><h2 id="解析sql" tabindex="-1">解析sql <a class="header-anchor" href="#解析sql" aria-label="Permalink to &quot;解析sql&quot;">​</a></h2><p>在正式的执行sql之前，MySQL会对sql进行解析。</p><ol><li><strong>词法分析</strong>，会把sql中的关键词和非关键词识别出来，例如，SQL语句 <code>select username from userinfo</code>，在分析之后，会得到4个Token，其中有2个Keyword，分别为select和from：</li><li><strong>语法分析</strong>，根据词法分析的结果，判断你这个sql语句是不是合法的，如果没问题就会构建出 SQL 语法树。</li></ol><p>如果你写的sql语句语法不正确，就会在解析器这个阶段报错。也就是说这个阶段主要还是判断语法，而不判断内容正确性，比如你查询了一个不存在的字段，也是不会报错的。</p><h2 id="执行sql" tabindex="-1">执行sql <a class="header-anchor" href="#执行sql" aria-label="Permalink to &quot;执行sql&quot;">​</a></h2><h3 id="预处理器" tabindex="-1">预处理器 <a class="header-anchor" href="#预处理器" aria-label="Permalink to &quot;预处理器&quot;">​</a></h3><ul><li>检查sql中的字段是否存在</li><li>将<code>select *</code>中的<code>*</code>扩展为表的所有列</li></ul><p>说明，在这里会对你实际的内容进行判断</p><h3 id="优化器" tabindex="-1">优化器 <a class="header-anchor" href="#优化器" aria-label="Permalink to &quot;优化器&quot;">​</a></h3><p><strong>优化器会决定这个sql的执行方案，比如是否利用索引，会利用哪个索引。</strong></p><p>要想知道优化器选择了哪个索引，我们可以在查询语句最前面加个 <code>explain</code> 命令，这样就会输出这条 SQL 语句的执行计划，然后执行计划中的 key 就表示执行过程中使用了哪个索引，比如：</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">EXPLAIN </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> employees </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> department_id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><table tabindex="0"><thead><tr><th>id</th><th>select_type</th><th>table</th><th>type</th><th>possible_keys</th><th>key</th><th>key_len</th><th>ref</th><th>rows</th><th>Extra</th></tr></thead><tbody><tr><td>1</td><td>SIMPLE</td><td>employees</td><td>ref</td><td>department_id</td><td>department_id</td><td>5</td><td>const</td><td>10</td><td>Using index</td></tr></tbody></table><p>可以看到这里利用到了department_id索引</p><p>如果查询语句的执行计划里的 key 为 null 说明没有使用索引，那就会全表扫描（type = ALL），这种查询扫描的方式是效率最低档次的，比如：</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">EXPLAIN </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> employees </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> last_name </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Smith&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>执行上述 <code>EXPLAIN</code> 语句后，MySQL会返回类似下面的执行计划结果：</p><table tabindex="0"><thead><tr><th>id</th><th>select_type</th><th>table</th><th>type</th><th>possible_keys</th><th>key</th><th>key_len</th><th>ref</th><th>rows</th><th>Extra</th></tr></thead><tbody><tr><td>1</td><td>SIMPLE</td><td>employees</td><td>ALL</td><td>NULL</td><td>NULL</td><td>NULL</td><td>NULL</td><td>1000</td><td>Using where</td></tr></tbody></table><h3 id="执行器" tabindex="-1">执行器 <a class="header-anchor" href="#执行器" aria-label="Permalink to &quot;执行器&quot;">​</a></h3><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><ul><li>连接器：建立连接，管理连接、校验用户身份；</li><li>查询缓存：查询语句如果命中查询缓存则直接返回，否则继续往下执行。MySQL 8.0 已删除该模块；</li><li>解析 SQL，通过解析器对 SQL 查询语句进行词法分析、语法分析，然后构建语法树，方便后续模块读取表名、字段、语句类型；</li><li>执行 SQL：执行 SQL 共有三个阶段： <ul><li>预处理阶段：检查表或字段是否存在；将 <code>select *</code> 中的 <code>*</code> 符号扩展为表上的所有列。</li><li>优化阶段：基于查询成本的考虑， 选择查询成本最小的执行计划；</li><li>执行阶段：根据执行计划执行 SQL 查询语句，从存储引擎读取记录，返回给客户端；</li></ul></li></ul><div style="display:none;" data-pagefind-meta="base64:JTdCJTIyZGF0ZSUyMiUzQTE3MTc1MDY0OTg5MzglN0Q="></div>`,45),l=[d];function n(h,p,r,o,k,c){return s(),i("div",null,l)}const u=t(e,[["render",n]]);export{y as __pageData,u as default};
